const coberturas = Array.isArray(this.grd_coberturas_seleccionadas)
  ? this.grd_coberturas_seleccionadas
  : [];

const result = coberturas
  .filter(c => c?.frm_cobertura_seleccionada === true)
  .map((c, idx) => {
    const texto = ((c?.frm_clausulas_principales ?? "") + "")
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#39;")
      .replace(/`/g, "&#96;");

    const modalId = `pm_modal_clausula_${idx}`;

    return {
      frm_clausulas_principales_codigo: c?.frm_cobertura_codigo ?? null,
      frm_clausulas_principales_cobertura: c?.frm_cobertura_nombre ?? null,
      frm_clausulas_principales_subcobertura: c?.frm_cobertura_categoria ?? null,
      frm_clausulas_principales_id: c?.frm_cobertura_id ?? null,
      frm_clausulas_principales_texto: c?.frm_clausulas_principales ?? "",
      frm_clausulas_principales_boton: `
        <button type="button"
          style="padding:6px 10px;border:1px solid #ccc;border-radius:6px;background:#fff;cursor:pointer; text-align:center"
          onclick="
            const id='${modalId}';
            const old=document.getElementById(id);
            if(old) old.remove();

            const overlay=document.createElement('div');
            overlay.id=id;
            overlay.style.position='fixed';
            overlay.style.inset='0';
            overlay.style.background='rgba(0,0,0,.5)';
            overlay.style.zIndex='99999';
            overlay.style.display='flex';
            overlay.style.alignItems='center';
            overlay.style.justifyContent='center';
            overlay.setAttribute('onclick','this.remove()');

            overlay.innerHTML=\`
              <div onclick='event.stopPropagation()'
                   style='width:min(900px,92vw);max-height:85vh;overflow:auto;background:#fff;border-radius:12px;box-shadow:0 10px 30px rgba(0,0,0,.3);padding:16px'>
                <div style='display:flex;justify-content:space-between;align-items:center;gap:12px;margin-bottom:12px'>
                  <div style='font-weight:600'>Cláusulas principales</div>
                  <button type='button'
                          onclick='document.getElementById(&quot;${modalId}&quot;).remove()'
                          style='border:none;background:transparent;font-size:20px;cursor:pointer;line-height:1'
                          aria-label='Cerrar'>&times;</button>
                </div>
                <pre style='margin:0;white-space:pre-wrap;font-family:inherit'>${texto || "(Sin texto)"}</pre>
              </div>\`;

            document.body.appendChild(overlay);
          "
        >Ver</button>
      `.trim()
    };
  });

return result;

// Fuentes
const sel = Array.isArray(this.grd_subcoberturas_seleccionadas)
  ? this.grd_subcoberturas_seleccionadas
  : [];

const slip = Array.isArray(this.grd_textos_slip)
  ? this.grd_textos_slip
  : [];

// Mapa: cobertura_id -> texto
const slipById = new Map(
  slip.map(s => [String(s?.frm_cobertura_id ?? ""), String(s?.frm_clausulas_principales ?? "")])
);

const slipByIdToNombre = new Map(
  slip.map(s => [String(s?.frm_cobertura_id ?? ""), String(s?.frm_subcobertura_nombre ?? "")])
);

// Si no hay selección, deja el grid vacío (o cambia a [baseRow] si quieres 1 fila visible)
if (!sel.length) return [];

// Construye grid destino
return sel
  .filter(r => r && r.frm_cobertura_seleccionada_subcobertura != null && r.frm_cobertura_seleccionada_subcobertura !== "")
  .map((r, idx) => {
    const subIdStr = String(r.frm_cobertura_seleccionada_subcobertura);
    const subIdInt = parseInt(subIdStr, 10);

    const raw = String(slipById.get(subIdStr) ?? "");
    const texto = raw
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#39;")
      .replace(/`/g, "&#96;");
    const nombreSubcobertura = slipByIdToNombre.get(subIdStr) || "Cláusula adicional";
    const modalId = `pm_modal_clausula_adic_${subIdStr}_${idx}`;

    return {
      row_id: `ta_${subIdStr}_${idx}`, // estable para el grid

      // Columnas del grid
      frm_clausulas_adicionales_codigo: isNaN(subIdInt) ? subIdStr : subIdInt,
      frm_clausulas_adicionales_cobertura: r.frm_cobertura_seleccionada_principal ?? "",
      frm_clausulas_adicionales_subcobertura: nombreSubcobertura,
      //frm_clausulas_adicionales_subcobertura: r.frm_cobertura_seleccionada_subcobertura,
      frm_clausulas_adicionales_texto: slipById.get(subIdStr) ?? "",
      // HTML con modal
      frm_clausulas_adicionales_boton: `
        <button type="button"
          style="padding:6px 10px;border:1px solid #ccc;border-radius:6px;background:#fff;cursor:pointer"
          onclick="
            const id='${modalId}';
            const old=document.getElementById(id);
            if(old) old.remove();

            const overlay=document.createElement('div');
            overlay.id=id;
            overlay.style.position='fixed';
            overlay.style.inset='0';
            overlay.style.background='rgba(0,0,0,.5)';
            overlay.style.zIndex='99999';
            overlay.style.display='flex';
            overlay.style.alignItems='center';
            overlay.style.justifyContent='center';
            overlay.setAttribute('onclick','this.remove()');

            overlay.innerHTML=\`
              <div onclick='event.stopPropagation()'
                   style='width:min(900px,92vw);max-height:85vh;overflow:auto;background:#fff;border-radius:12px;box-shadow:0 10px 30px rgba(0,0,0,.3);padding:16px'>
                <div style='display:flex;justify-content:space-between;align-items:center;gap:12px;margin-bottom:12px'>
                  <div style='font-weight:600'>Cláusulas adicionales</div>
                  <button type='button'
                          onclick='document.getElementById(&quot;${modalId}&quot;).remove()'
                          style='border:none;background:transparent;font-size:20px;cursor:pointer;line-height:1'
                          aria-label='Cerrar'>&times;</button>
                </div>
                <pre style='margin:0;white-space:pre-wrap;font-family:inherit'>${texto || "(Sin texto)"}</pre>
              </div>\`;

            document.body.appendChild(overlay);
          "
        >Ver</button>
      `.trim()
    };
  });

